def schedule_pods(pods, nodes):
    assignments = {}
    pod_specs = {p["name"]: p for p in pods}
    nodes = dict(nodes) # Convert list to dict for easier lookup by name

    # Create a list of nodes sorted by remaining resources (smallest remaining first)
    active_nodes = sorted([(n['cpu'], n['mem'], n['name']) for n in nodes.values()])

    for pod_name, pod in pod_specs.items():
        best_node = None

        # Iterate through sorted nodes and find the first fit with max remaining space
        for rank, (rem_cpu, rem_mem, node_name) in enumerate(active_nodes):
            if rem_cpu >= pod['cpu'] and rem_mem >= pod['mem']:
                best_node = node_name
                break

        if best_node and nodes[best_node]['cpu'] >= pod['cpu'] and nodes[best_node]['mem'] >= pod['mem']:
            assignments[pod_name] = best_node
        else:
            assignments[pod_name] = None

    return assignments
