def schedule_pods(pods, nodes):
    node_usage = defaultdict(lambda: {"cpu": 0, "mem": 0})
    for n in nodes:
        node_usage[n["name"]] = {"capacity": {"cpu": n["cpu"], "mem": n["mem"]}, "used": {"cpu": 0, "mem": 0}}

    assignments = {}
    sorted_pods = sorted(pods, key=lambda x: -x["cpu"] - x["mem"]) # Prioritize larger pods

    for pod in sorted_pods:
        for node_name in sorted(node_usage.keys()):
            node = node_usage[node_name]
            if (node["capacity"]["cpu"] - node["used"]["cpu"] >= pod["cpu"] and 
                node["capacity"]["mem"] - node["used"]["mem"] >= pod["mem"]):

                for key in ["cpu", "mem"]:
                    node["used"][key] += pod[key]

                assignments[pod["name"]] = node_name
                break
        if pod["name"] not in assignments:
            assignments[pod["name"]] = None
